+// ============================================================================
+// Test 1: Configure + handshake lifecycle
+// ============================================================================
+
+/// Configure the connector and perform a handshake, verifying success.
+#[fcp_async_core::runtime::test]
+async fn e2e_connector_configure_and_handshake() {
